@startuml
' Define styles for different types of classes
class "C" {
  background-color: #d4edda;
  border-color: #c3e6cb;
}

class "I" {
  background-color: #e2e3f5;
  border-color: #d6d8db;
}

' Define the main classes and their relationships
class "Application" {
  "C"
}

class "AccountService" {
  "C"
}

class "RelationService" {
  "C"
}

class "Category" {
  "I"
}

class "TransactionService" {
  "C"
}

class "Family" {
  "C"
}

class "CategoryService" {
  "C"
}

class "Relation" {
  "C"
}

class "FamilyService" {
  "C"
}

class "FamilyMember" {
  "C"
}

class "Account" {
  "I"
}

class "AccountData" {
  "C"
}

class "Transaction" {
  "I"
}

class "MoneyValue" {
  "C"
}

' Define the package folders
package "controllers" {
  "Application"
}

package "category" {
  "Category"
}

package "accounts" {
  "Account"
}

' Define the relationships
"Application" --> "AccountService" : has
"Application" --> "RelationService" : has
"Application" --> "CategoryService" : has list
"Application" --> "Relation" : has list
"Application" --> "FamilyService" : has list
"RelationService" --> "Category" : implements
"RelationService" --> "Relation" : has
"CategoryService" --> "Category" : handles
"FamilyService" --> "Family" : has list
"FamilyService" --> "FamilyMember" : handles
"FamilyMember" --> "Account" : has list
"AccountService" --> "AccountData" : implements
"AccountService" --> "Transaction" : handles
"TransactionService" --> "Transaction" : handles
"Transaction" --> "MoneyValue" : contains
"Account" <|-- "AccountData" : contains
"Account" <|-- "Transaction" : contains

@enduml
